package com.oyuki.exportrequest.entity; import com.oyuki.exportrequest.enums.ExportRequestStatus; import com.oyuki.user.entity.User; import jakarta.persistence.*; import lombok.*; import java.time.LocalDateTime; @Entity @Table(name="export_requests") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class ExportRequest { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="customer_id") private User customer; @Column(nullable=false,length=160) private String productName; @Column(nullable=false,length=120) private String destinationCountry; @Column(nullable=false,length=100) private String quantity; @Column(length=3000) private String notes; @Enumerated(EnumType.STRING) @Column(nullable=false,length=30) @Builder.Default private ExportRequestStatus status=ExportRequestStatus.SUBMITTED; @Column(length=1500) private String adminNote; private LocalDateTime createdAt; private LocalDateTime updatedAt; @PrePersist void create(){createdAt=updatedAt=LocalDateTime.now();} @PreUpdate void update(){updatedAt=LocalDateTime.now();} }